230→export const uploadJournalContentService = async(
231→    content,
232→    title,
233→    userId,
234→    remixSourceJournalId = null,
235→    isRemix = false,
236→    promptId = null
237→) =>{
238→    if(!userId){
239→        console.error('userId is undefined');
240→        throw {status: 400, error: 'userId is undefined'};
241→    }
242→
243→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
244→
245→    if(!trimmedTitle){
246→        console.error('title is missing!');
247→        throw {status: 400, error: 'title is missing!'};
248→    }
249→
250→    const shouldSaveRemixMetadata = Boolean(
251→        remixSourceJournalId
252→        && typeof remixSourceJournalId === 'string'
253→        && remixSourceJournalId.trim()
254→    );
255→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
256→
257→    if(!content){
258→        console.error('content is missing for text post!');
259→        throw {status: 400, error: 'content is missing for text post'};
260→    }
261→
262→    const parseData = parseTextContentSafely(content);
263→    if(!parseData){
264→        console.error('error while parsing text content data');
265→        throw {status: 400, error: 'error while parsing text content data'};
266→    }
267→
268→    const embeddingBody = parseData.wholeText || '';
269→    const preview_text = parseData.slicedText || '';
270→    const thumbnail_url = parseData.firstImage?.src || null;
271→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
272→    const payload = {
273→        user_id: userId,
274→        title: trimmedTitle,
275→        post_type: POST_TYPE_TEXT,
276→        content: content,
277→        preview_text,
278→        thumbnail_url,
279→        reading_time,
280→        status: 'published',
281→        published_at: new Date().toISOString(),
282→    };
283→
284→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
285→
286→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
287→        console.error('error while generating embeddings on a post!');
288→        throw {status: 400, error: 'error while generating embeddings on a post!'};
289→    }
290→
291→    const insertPayload = {
292→        ...payload,
293→        embeddings: embeddingResult
294→    };
295→
296→    if(normalizedIsRemix){
297→        insertPayload.is_remix = true;
298→    }
299→    if(shouldSaveRemixMetadata){
300→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
301→    }
302→    if(promptId){
303→        const parsedPromptId = parseInt(promptId, 10);
304→        if(!isNaN(parsedPromptId)){
305→            insertPayload.prompt_id = parsedPromptId;
306→        }
307→    }
308→
309→    let insertResult = await supabase
310→    .from('journals')
311→    .insert(insertPayload)
312→    .select('id')
313→    .single();
314→
315→    let error = insertResult.error;
316→
317→    if(error){
318→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
319→        if(missingRemixColumns){
320→            const fallbackPayload = {
321→                ...payload,
322→                embeddings: embeddingResult
323→            };
324→
325→            insertResult = await supabase
326→            .from('journals')
327→            .insert(fallbackPayload)
328→            .select('id')
329→            .single();
330→            error = insertResult.error;
331→        }
332→    }
333→
334→    if(error){
335→        console.error('supabase error while uploading content:',error.message);
336→        throw {status: 500, error: 'supabase error while uploading content'};
337→    }
338→
339→    const journalId = insertResult.data?.id;
340→
341→    // Non-fatal: send mention notifications
342→    if(journalId){
343→        try {
344→            const mentionedUserIds = extractMentionUserIds(content);
345→            const filtered = mentionedUserIds
346→                .filter(id => id !== userId)
347→                .slice(0, 50);
348→
349→            if(filtered.length > 0){
350→                const notifRows = filtered.map(receiverId => ({
351→                    sender_id: userId,
352→                    receiver_id: receiverId,
353→                    type: 'mention',
354→                    journal_id: journalId,
355→                    read: false
356→                }));
357→
358→                const {error: notifError} = await supabase
359→                    .from('notifications')
360→                    .insert(notifRows);
361→
362→                if(notifError){
363→                    console.error('[mentions] new post: insert failed:', notifError.message);
364→                }
365→            }
366→        } catch (mentionErr) {
367→            console.error('[mentions] new post error:', mentionErr?.message || mentionErr);
368→        }
369→    }
370→
371→    // Non-fatal: record publish for writing streak
372→    let streakResult = null;
373→    try {
374→        const { recordPublishForStreak } = await import('./streakService.js');
375→        streakResult = await recordPublishForStreak(userId);
376→    } catch (streakErr) {
