101→        .from('opinions')
102→        .select(MY_OPINION_SELECT)
103→        .order('id', { ascending: false })
104→        .limit(parsedLimit + 1)
105→        .eq('user_id', req.userId)
106→        .is('parent_id', null);
107→
108→    if (before) query = query.lt('id', before);
109→
110→    const { data, error } = await query;
