  5→const CONFETTI_COLORS = ['#D4A853', '#C4943E', '#E0BA6A', '#FAF9F6', '#8A9E7A'];
  6→
  7→const FirstActionStep = ({ goBack, writingGoal, onComplete }) => {
  8→    const canvasRef = useRef(null);
  9→
 10→    useEffect(() => {
 11→        if (!canvasRef.current) return;
 12→        const myConfetti = confetti.create(canvasRef.current, { resize: true });
 13→
 14→        const timer = setTimeout(() => {
 15→            myConfetti({
 16→                particleCount: 100,
 17→                spread: 120,
 18→                startVelocity: 30,
 19→                ticks: 600,
 20→                gravity: 0.5,
 21→                scalar: 1.3,
 22→                origin: { x: 0.5, y: 0.35 },
 23→                colors: CONFETTI_COLORS,
 24→            });
 25→        }, 300);
 26→
 27→        return () => clearTimeout(timer);
 28→    }, []);
 29→
 30→    const getPrimaryCta = () => {
 31→        switch (writingGoal) {
 32→            case 'journal':
 33→            case 'publish':
 34→                return { label: 'Write your first post', action: 'write' };
 35→            case 'stories':
 36→                return { label: 'Start a story', action: 'story' };
 37→            default:
 38→                return { label: 'Explore Iskrib', action: 'explore' };
 39→        }
 40→    };
 41→
 42→    const getSecondaryCta = () => {
 43→        switch (writingGoal) {
 44→            case 'journal':
 45→            case 'publish':
 46→                return { label: 'Explore first', action: 'explore' };
 47→            case 'stories':
 48→                return { label: 'Write a post instead', action: 'write' };
 49→            default:
 50→                return { label: 'Write your first post', action: 'write' };
 51→        }
 52→    };
