 83→        .select(NOTIFICATION_JOURNAL_SELECT)
 84→        .eq('receiver_id', userId)
 85→        .order('created_at', { ascending: false })
 86→        .order('id', { ascending: false })
 87→        .limit(fetchLimit);
 88→
 89→    let opinionQuery = supabase
 90→        .from('notification_opinions')
 91→        .select(NOTIFICATION_OPINION_SELECT)
 92→        .eq('receiver_id', userId)
 93→        .order('created_at', { ascending: false })
 94→        .order('id', { ascending: false })
 95→        .limit(fetchLimit);
 96→
 97→    if (unreadOnly) {
 98→        journalQuery = journalQuery.eq('read', false);
 99→        opinionQuery = opinionQuery.eq('read', false);
100→    }
101→
102→    if (before) {
103→        journalQuery = journalQuery.lt('created_at', before);
104→        opinionQuery = opinionQuery.lt('created_at', before);
105→    }
106→
107→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
108→
109→    if (journalResult.error) {
110→        console.error('error fetching notifications:', journalResult.error);
111→        throw { status: 500, error: 'error fetching data from notification table' };
112→    }
113→    if (opinionResult.error) {
114→        console.error('error fetching opinion notifications:', opinionResult.error);
115→        throw { status: 500, error: 'error fetching data from notification_opinions table' };
116→    }
117→
118→    const journalNotifs = (journalResult.data || []).map(n => ({ ...n, source: 'journal' }));
119→    const opinionNotifs = (opinionResult.data || []).map(n => ({ ...n, source: 'opinion' }));
120→
121→    const merged = [...journalNotifs, ...opinionNotifs]
122→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
123→
124→    // Likes/bookmarks lookup only for journal notifications
125→    const journalIds = [...new Set(
126→        merged
127→            .filter(n => n.source === 'journal')
128→            .map(n => n.journal_id)
129→            .filter(Boolean)
130→    )];
131→
132→    let hasLikedResult = [];
133→    let hasBookMarkedResult = [];
134→    if (journalIds.length > 0) {
135→        const [hasLiked, hasBookMarked] = await Promise.all([
136→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
137→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
138→        ]);
139→
140→        if (hasLiked.error || hasBookMarked.error) {
141→            console.error('supabase error fetching likes/bookmarks:', hasLiked.error || hasBookMarked.error);
142→        }
143→        hasLikedResult = hasLiked.data || [];
144→        hasBookMarkedResult = hasBookMarked.data || [];
145→    }
146→
147→    const likedSet = new Set(hasLikedResult.map(l => l.journal_id));
148→    const bookmarkedSet = new Set(hasBookMarkedResult.map(b => b.journal_id));
149→
150→    const formatted = merged.map(notif => decorateNotificationMedia({
151→        ...notif,
152→        hasLiked: notif.source === 'journal' ? likedSet.has(notif.journal_id) : false,
153→        hasBookMarked: notif.source === 'journal' ? bookmarkedSet.has(notif.journal_id) : false
154→    }));
155→
156→    const hasMore = formatted.length > limit;
157→    const data = hasMore ? formatted.slice(0, limit) : formatted;
158→
159→    return { data, hasMore };
160→};
