602→    const { data: rpcData, error } = await supabase.rpc('get_following_feed', {
603→        p_user_id: userId,
604→        p_limit: parsedLimit + 1,
605→        p_before: before || null
606→    });
607→
608→    if (error) {
609→        console.error('supabase error fetching following feed:', error.message);
610→        throw { status: 500, error: 'supabase error fetching following feed' };
611→    }
612→
613→    if (!rpcData || rpcData.length === 0) {
614→        return { data: [], hasMore: false };
615→    }
616→
617→    // Reshape RPC rows to match PostgREST format the client expects
618→    const data = rpcData.map(row => ({
619→        id: row.id,
620→        user_id: row.user_id,
621→        title: row.title,
622→        preview_text: row.preview_text || '',
623→        thumbnail_url: row.thumbnail_url || null,
624→        post_type: row.post_type,
625→        created_at: row.created_at,
626→        privacy: row.privacy,
627→        views: row.views,
628→        is_repost: row.is_repost,
629→        repost_source_journal_id: row.repost_source_journal_id,
630→        repost_caption: row.repost_caption,
631→        prompt_id: row.prompt_id,
632→        users: { id: row.user_obj_id, name: row.user_name, image_url: row.user_image_url, badge: row.user_badge },
