635→        comment_count: [{ count: Number(row.comment_count) }],
636→        bookmark_count: [{ count: Number(row.bookmark_count) }]
637→    }));
638→
639→    // Step 2: Personalization (same pattern as getJournalsService — operates on small result set)
640→    const journalIds = data.map(j => j.id);
641→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
642→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
643→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
644→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
645→    ]);
646→
647→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
648→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
649→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
650→
651→    await attachRepostSources(data);
652→
653→    const formattedData = data.map(journal => ({
654→        ...journal,
655→        has_liked: userHasLikedSet.has(journal.id),
656→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
657→        user_reaction: userReactionMap.get(journal.id) || null
658→    }));
659→    const optimizedData = decorateJournalCollection(formattedData, JOURNAL_MEDIA_USAGE.feed);
660→
661→    const hasMore = data.length > parsedLimit;
662→    const slicedData = hasMore ? optimizedData.slice(0, parsedLimit) : optimizedData;
663→
664→    return { data: slicedData, hasMore };
665→}
