 11→const SidebarOpinions = ({openEditor}) =>{
 12→    const {user, session, openAuthModal} = useAuth();
 13→
 14→    const handleOpenEditor = () =>{
 15→        if(!session) return openAuthModal();
 16→        openEditor();
 17→    }
 18→    const navigate = useNavigate();
 19→
 20→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
 21→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
 22→        if(!session){
 23→            e.stopPropagation();
 24→            return openAuthModal();
 25→        }
 26→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
 27→    };
 28→
 29→    const {data, isLoading, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 30→        queryKey: ['getOpinions'],
 31→        queryFn: ({pageParam = null}) => getOpinions(pageParam, 5),
 32→        getNextPageParam: (lastPage) =>{
 33→            if(lastPage?.hasMore){
 34→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
 35→                return lastOpinion.id;
 36→            } else {
 37→                return undefined
 38→            }
 39→        },
 40→        refetchOnWindowFocus: false,
 41→        staleTime: 1000 * 60 * 5,
 42→    });
 43→
 44→    const handleClickSeeMore = () =>{
 45→        if(!isLoading && !isFetchingNextPage){
 46→            fetchNextPage();;
 47→        }
 48→        
 49→    }
 50→
 51→    const handleClickContent = (e, opinionId, userId) =>{
 52→        e.stopPropagation();
 53→        if(!session) return openAuthModal();
 54→        navigate('/home/opinionsViewer', {
 55→            state: {
 56→                opinionId: opinionId,
 57→                userId: userId
 58→            }
 59→        })
 60→    }
 61→
 62→    useEffect(() => {
 63→        // console.log(data)
 64→    }, [data])
 65→
 66→    const getUserHandle = (opinionUser) => {
 67→        if(!opinionUser?.user_email) return null;
 68→        const handle = opinionUser.user_email.split('@')[0];
 69→        return handle ? `@${handle}` : null;
 70→    }
 71→
 72→    const opinions = data?.pages.flatMap((page) => page.data) || [];
 73→    
 74→    if(opinions.length === 0){
 75→        return(
 76→            <div className='side-bar-opinions-parent-container'>
 77→                <div className='signal-container'>
 78→                    <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
 79→                    <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
 80→                        Write opinions
 81→                    </button>
 82→                </div>
 83→                <div className='latest-opinions-container'>
 84→                    <div className='latest-opinions-header'>
 85→                        Latest opinions
 86→                    </div>
 87→                    <div className='sidebar-opinions-cards-container'>
 88→                        No opinions availabe
 89→                    </div>
 90→                </div>
 91→            </div>
 92→        )
 93→    }
 94→    if(isLoading){
 95→        return(
 96→            <div className='side-bar-opinions-parent-container'>
 97→                <div className='opinions-loading-container'>
 98→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
 99→                </div>
100→            </div>
101→        )
102→    }
103→    return(
104→        <>
105→        <div className="side-bar-opinions-parent-container">
106→            <div className='signal-container'>
107→                <p className='signal-header'>“Share what you believe. This is a free-speech space.”</p>
108→                <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
109→                    Write opinions
110→                </button>
111→            </div>
112→
113→            <div className='latest-opinions-container'>
114→                <div className='latest-opinions-header'>
115→                    Latest opinions
116→                </div>
117→                <div className='sidebar-opinions-cards-container'>
118→                    {opinions.map((opinionsData) => {
119→                        const handle = getUserHandle(opinionsData?.users);
120→                        return (
121→                            <div key={opinionsData.id} className="so-card-wrapper">
122→                                <div className="so-card so-card--flat">
123→                                    <div className="so-card-content">
124→                                        <div className="so-user-row">
125→                                            <div className="so-user-meta">
126→                                                <div className={`so-avatar-outer ${opinionsData.users.badge === 'legend' ? 'avatar-ring-legend' : opinionsData.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
127→                                                    <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-avatar" src={opinionsData.users.image_url || "../../assets/profile.jpg"} alt={`${opinionsData?.users?.name || "User"} profile picture`} />
128→                                                </div>
129→                                                <div className="so-name-block">
130→                                                    <div className="so-name-line">
131→                                                        <span onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-username">{opinionsData.users.name}</span>
132→                                                        <VerifiedBadge badge={opinionsData.users.badge} size={14} />
133→                                                    </div>
134→                                                    {handle && (
135→                                                        <span className="so-handle">{handle}</span>
136→                                                    )}
137→                                                </div>
138→                                            </div>
139→                                        </div>
140→                                        <div className="so-body" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
141→                                            {opinionsData.opinion}
142→                                        </div>
143→                                        <div className="so-meta-bar">
144→                                            <span className="so-reply-pill" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinionsData.id, userId: opinionsData.user_id } }); }}>
145→                                                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
146→                                                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
147→                                                </svg>
148→                                                Reply
149→                                            </span>
150→                                        </div>
151→                                    </div>
152→                                </div>
153→                            </div>
154→                        )
155→                    })}
156→                    {hasNextPage && (
157→                        <div onClick={() => handleClickSeeMore()} className='see-fullpage-bttn'>
158→                            See more
159→                        </div>
160→                    )}
161→                    
162→                </div>
163→            </div>
164→        </div>
165→        </>
166→    )
167→}
168→export default SidebarOpinions;
