804→export const getJournalByIdService = async (journalId, userId, { includeRepostContent = false } = {}) => {
805→    if (!journalId) {
806→        console.error('journalId is undefined');
807→        throw { status: 400, error: 'journalId is undefined' };
808→    }
809→
810→    const { data: journal, error: journalError } = await supabase
811→        .from('journals')
812→        .select(JOURNAL_WITH_COUNTS_SELECT)
813→        .eq('id', journalId)
814→        .eq('privacy', 'public')
815→        .maybeSingle();
816→
817→    if (journalError) {
818→        console.error('supabase error while fetching journal by id:', journalError.message);
819→        throw { status: 500, error: 'supabase error while fetching journal by id' };
820→    }
821→
822→    if (!journal) {
823→        return null;
824→    }
825→
826→    await attachRepostSources(journal, { includeContent: includeRepostContent });
827→
828→    let hasLiked = false;
829→    let hasBookmarked = false;
830→    let userReaction = null;
831→
832→    if (userId) {
833→        const [likeResult, bookmarkResult, reactionResult] = await Promise.all([
834→            supabase
835→                .from('likes')
836→                .select('journal_id', { count: 'exact', head: true })
837→                .eq('journal_id', journalId)
838→                .eq('user_id', userId),
839→            supabase
840→                .from('bookmarks')
841→                .select('journal_id', { count: 'exact', head: true })
842→                .eq('journal_id', journalId)
843→                .eq('user_id', userId),
844→            supabase
845→                .from('reactions')
846→                .select('reaction_type')
847→                .eq('journal_id', journalId)
848→                .eq('user_id', userId)
849→                .maybeSingle()
850→        ]);
851→
852→        if (likeResult.error || bookmarkResult.error) {
853→            console.error(
854→                'supabase error while fetching journal interactions:',
855→                likeResult.error?.message || bookmarkResult.error?.message
856→            );
857→            throw { status: 500, error: 'supabase error while fetching journal interactions' };
858→        }
859→
860→        hasLiked = (likeResult.count || 0) > 0;
861→        hasBookmarked = (bookmarkResult.count || 0) > 0;
862→        userReaction = reactionResult.data?.reaction_type || null;
863→    }
864→
865→    return decorateJournalMedia({
866→        ...journal,
867→        has_liked: hasLiked,
868→        has_bookmarked: hasBookmarked,
869→        user_reaction: userReaction
870→    }, JOURNAL_MEDIA_USAGE.detail);
871→}
