897→export const getUserJournalsService = async(limit, before, userId) =>{
898→    if(!userId){
899→        console.error('userid is undefined');
900→        throw {status: 400, error: 'userid is undefined'};
901→    }
902→
903→    if(isNaN(limit)|| limit > 20 || limit < 1){
904→        console.error('limit should be integer and not more than 20 and less than 1')
905→        throw {status: 400, error: 'limit should be integer and not more than 20 and less than 1'};
906→    }
907→
908→    const parsedLimit = parseInt(limit);
909→
910→    let query = supabase
911→    .from('journals')
912→    .select(JOURNAL_METADATA_WITH_COUNTS_SELECT)
913→    .eq('user_id', userId)
914→    .eq('status', 'published')
915→    .order('created_at', {ascending: false})
916→    .order('id', {ascending: false})
917→    .limit(parsedLimit + 1)
918→
919→    if(before){
920→        query = query.lt('created_at', before);
921→    }
922→
923→    const {data: journals, error: errorJournals} = await query;
924→
925→    if(errorJournals){
926→        console.error('supabase error while fetching user journals:', errorJournals.message);
927→        throw {status: 500, error: 'supabase error while fetching user journals'};
928→    }
929→
930→    const journalIds = journals?.map((journal) => journal.id);
931→
932→    if(journalIds.length === 0){
933→        const data = {data: [], hasMore: false};
934→        return data;
935→    }
936→
937→    await attachRepostSources(journals);
938→
939→    let userLikesPromise;
940→    let userBookmarksPromise;
941→    let userReactionsPromise;
942→    if(journalIds){
943→        userLikesPromise = supabase
944→        .from('likes')
945→        .select('journal_id')
946→        .in('journal_id', journalIds)
947→        .eq('user_id', userId)
948→
949→        userBookmarksPromise = supabase
950→        .from('bookmarks')
951→        .select('journal_id')
952→        .in('journal_id', journalIds)
953→        .eq('user_id', userId)
954→
955→        userReactionsPromise = supabase
956→        .from('reactions')
957→        .select('journal_id, reaction_type')
958→        .in('journal_id', journalIds)
959→        .eq('user_id', userId)
960→    }
961→
962→    const [userLikesResult, userBookmarksResult, userReactionsResult] = await Promise.all([
963→        userLikesPromise, userBookmarksPromise, userReactionsPromise
964→    ])
965→
966→    const {data: userLikes, error: errorUserLikeResult} = userLikesResult;
967→    const {data: userBookmarks, error: errorBookmarksResult} = userBookmarksResult;
968→    const {data: userReactions, error: errorReactionsResult} = userReactionsResult;
969→
970→    if(errorBookmarksResult || errorUserLikeResult || errorReactionsResult){
971→        console.error('supabase error:', errorBookmarksResult?.message || errorUserLikeResult?.message || errorReactionsResult?.message);
972→        return {status: 500, error: 'supabase error while fetching userlikes or userbookmarks'}
973→    }
974→
975→    const userLikesSet = new Set(userLikes?.map((j) => j.journal_id) || []);
976→    const userBookmarksSet = new Set(userBookmarks?.map((j) => j.journal_id) || []);
977→    const userReactionMap = new Map((userReactions || []).map((r) => [r.journal_id, r.reaction_type]));
978→
979→    const formattedData = journals?.map((journal) => ({
980→        ...journal,
981→        has_liked: userLikesSet.has(journal.id),
982→        has_bookmarked: userBookmarksSet.has(journal.id),
983→        user_reaction: userReactionMap.get(journal.id) || null
984→    }));
985→    const optimizedData = decorateJournalCollection(formattedData, JOURNAL_MEDIA_USAGE.feed);
986→
987→    const hasMore = journals.length > parsedLimit;
988→    const slicedData = hasMore ? optimizedData.slice(0, parsedLimit) : optimizedData;
989→
990→    const journalData = {data: slicedData, hasMore: hasMore};
991→
992→    return journalData;
993→}
