 28→const verifyStoryOwnership = async (storyId, userId) => {
 29→    const { data, error } = await supabase
 30→        .from('stories')
 31→        .select('author_id')
 32→        .eq('id', storyId)
 33→        .single();
 34→
 35→    if (error || !data) {
 36→        throw { status: 404, error: 'story not found' };
 37→    }
