355→export const addFollowsService = async(followerId, followingId) => {
356→    if(!followerId || !followingId){
357→        throw new AppError(400, 'followerId or followingId is undefined');
358→    }
359→
360→    const {data: existing, error: errorExisting} = await supabase
361→    .from('follows')
362→    .select('*')
363→    .eq('follower_id', followerId)
364→    .eq('following_id', followingId)
365→    .maybeSingle();
366→
367→    if(errorExisting){
368→        console.error('supabase error while checking existing following:', errorExisting.message);
369→        throw new AppError(500, 'supabase error while checking existing following');
370→    }
371→
372→    if(existing){
373→        const {error: errorRemoveData} = await supabase
374→        .from('follows')
375→        .delete()
376→        .eq('follower_id', followerId)
377→        .eq('following_id', followingId)
378→
379→        if(errorRemoveData){
380→            console.error('supabase error while deleting follow data:', errorRemoveData.message);
381→            throw new AppError(500, 'supabase error while deleting follow data');
382→        }
383→
384→        return {message: 'deleted follows data'};
385→    } else {
386→        const {error: errorInserData} = await supabase
387→        .from('follows')
388→        .insert({
389→            follower_id: followerId,
390→            following_id: followingId,
391→        })
392→
393→        if(errorInserData){
394→            console.error('supabase error while inserting follow data:', errorInserData.message);
395→            throw new AppError(500, 'supabase error while inserting follow data');
396→        }
397→
398→        // Create follow notification (skip if self-follow)
399→        if (followerId !== followingId) {
400→            await supabase
401→                .from('notifications')
402→                .insert({
403→                    sender_id: followerId,
404→                    receiver_id: followingId,
405→                    type: 'follow',
406→                    read: false
407→                });
408→        }
409→
410→        return {message: 'success'};
411→    }
412→}
