 1→import supabase from "./supabase.js";
 2→
 3→/**
 4→ * Get today's writing prompt.
 5→ * Uses dayOfYear % promptCount for deterministic rotation.
 6→ */
 7→export const getTodaysPromptService = async () => {
 8→    // Get total prompt count
 9→    const { count, error: countErr } = await supabase
10→        .from('writing_prompts')
11→        .select('id', { count: 'exact', head: true });
12→
13→    if (countErr || !count || count === 0) {
14→        console.error('error getting prompt count:', countErr?.message);
15→        return null;
16→    }
17→
18→    // Calculate today's prompt index
19→    const now = new Date();
20→    const startOfYear = new Date(now.getFullYear(), 0, 0);
21→    const diff = now - startOfYear;
22→    const dayOfYear = Math.floor(diff / (1000 * 60 * 60 * 24));
23→    const promptIndex = dayOfYear % count;
24→
25→    // Fetch the prompt at that index (ordered by id ASC)
26→    const { data, error } = await supabase
27→        .from('writing_prompts')
28→        .select('*')
29→        .order('id', { ascending: true })
30→        .range(promptIndex, promptIndex)
31→        .single();
32→
33→    if (error) {
34→        console.error('error fetching today\'s prompt:', error.message);
35→        return null;
36→    }
37→
38→    return data;
39→};
40→
41→/**
42→ * Get journals that responded to a specific prompt.
43→ */
44→export const getPromptResponsesService = async (promptId, limit = 5, before = null) => {
45→    if (!promptId) return { responses: [], count: 0 };
46→
47→    const parsedLimit = Math.min(Math.max(parseInt(limit, 10) || 5, 1), 50);
48→
49→    let query = supabase
50→        .from('journals')
51→        .select(`
52→            id,
53→            title,
54→            created_at,
55→            user_id,
56→            users(id, name, image_url, badge)
57→        `, { count: !before ? 'exact' : undefined })
58→        .eq('prompt_id', promptId)
59→        .eq('privacy', 'public')
60→        .order('created_at', { ascending: false })
61→        .order('id', { ascending: false })
62→        .limit(parsedLimit + 1);
63→
64→    if (before) {
65→        query = query.lt('created_at', before);
66→    }
67→
68→    const { data, error, count } = await query;
69→
70→    if (error) {
71→        console.error('error fetching prompt responses:', error.message);
72→        return { responses: [], count: 0 };
73→    }
74→
75→    const hasMore = (data || []).length > parsedLimit;
76→    const responses = hasMore ? data.slice(0, parsedLimit) : (data || []);
77→
78→    const result = { responses, hasMore };
79→    if (!before) {
80→        result.count = count || 0;
81→
82→        const { count: totalResponses } = await supabase
83→            .from('journals')
84→            .select('id', { count: 'exact', head: true })
85→            .eq('prompt_id', promptId)
86→            .eq('privacy', 'public');
87→        // Approximate unique count — for prompts, count of responses is close to unique users
88→        // since each user typically responds once
89→        result.uniqueCount = totalResponses || 0;
90→    }
91→
92→    return result;
93→};
