 51→export const useBookMarkMutation = (session, userId) => {
 52→    const queryClient = useQueryClient();
 53→    const inFlightBookmarkIdsRef = useRef(new Set());
 54→
 55→    const mutation = useMutation({
 56→        mutationFn: (data) => addBookmark(session?.access_token, data),
 57→
 58→        onMutate: async(data) =>{
 59→            queryClient.cancelQueries({ queryKey: ['journals'] });
 60→            queryClient.cancelQueries({ queryKey: ['journals-following'] });
 61→            queryClient.cancelQueries({ queryKey: ['journals-for-you'] });
 62→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
 63→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
 64→
 65→            const previousData = [
 66→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
 67→                ...queryClient.getQueriesData({ queryKey: ['journals-following'] }),
 68→                ...queryClient.getQueriesData({ queryKey: ['journals-for-you'] }),
 69→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
 70→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
 71→            ];
 72→
 73→            const updater = (journal) => {
 74→                if(journal.id !== data.journalId) return journal;
 75→
 76→                const isBookmarked = normalizeInteractionFlag(journal?.has_bookmarked);
 77→                const count = normalizeCount(journal?.bookmark_count?.[0]?.count);
 78→                const nextCount = getNextToggleCount(isBookmarked, count);
 79→
 80→                return{
 81→                    ...journal,
 82→                    has_bookmarked: !isBookmarked,
 83→                    bookmark_count: [{count: nextCount}]
 84→                };
 85→            };
 86→
 87→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 88→            queryClient.setQueriesData({ queryKey: ['journals-following'] }, (old) => updateInfiniteJournalsCache(old, updater));
 89→            queryClient.setQueriesData({ queryKey: ['journals-for-you'] }, (old) => updateInfiniteJournalsCache(old, updater));
 90→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 91→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 92→
 93→            return {previousData};
 94→        },
 95→        onError: (err,data, context) =>{
 96→            context?.previousData?.forEach(([key, value]) => {
 97→                queryClient.setQueryData(key, value);
 98→            });
 99→        },
100→    });
101→
102→    const guardedMutate = (variables, options) => {
103→        const journalKey = toJournalKey(variables?.journalId);
104→        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
105→            return;
106→        }
107→
108→        if(journalKey){
109→            inFlightBookmarkIdsRef.current.add(journalKey);
110→        }
111→
112→        mutation.mutate(variables, {
113→            ...options,
114→            onSettled: (data, error, vars, context) => {
115→                if(journalKey){
116→                    inFlightBookmarkIdsRef.current.delete(journalKey);
117→                }
118→                options?.onSettled?.(data, error, vars, context);
119→            }
120→        });
121→    };
122→
123→    const guardedMutateAsync = async (variables, options) => {
124→        const journalKey = toJournalKey(variables?.journalId);
125→        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
126→            return {message: 'skipped'};
127→        }
128→
129→        if(journalKey){
130→            inFlightBookmarkIdsRef.current.add(journalKey);
131→        }
132→
133→        try {
134→            return await mutation.mutateAsync(variables, options);
135→        } finally {
136→            if(journalKey){
137→                inFlightBookmarkIdsRef.current.delete(journalKey);
138→            }
139→        }
140→    };
141→
142→    return {
143→        ...mutation,
144→        mutate: guardedMutate,
145→        mutateAsync: guardedMutateAsync
146→    };
147→}
