**`client/src/components/mentions/useTextareaMention.js`**

This is the glue hook for `<textarea>` elements. It takes a ref to the textarea, the current `value`, and a `setValue` setter. It returns `{ mentionProps, dropdownProps }` for spreading onto the textarea and the dropdown respectively.

```js
// client/src/components/mentions/useTextareaMention.js
import { useState, useRef, useCallback, useEffect } from 'react';
import { useMentionAutocomplete } from './useMentionAutocomplete';

const MENTION_TRIGGER_REGEX = /@([\w-]*)$/;

export function useTextareaMention(value, setValue, textareaRef) {
    const [cursorPosition, setCursorPosition] = useState(null);
    const [dropdownPosition, setDropdownPosition] = useState(null);
    const mirrorRef = useRef(null);

    const { query, results, isOpen, isLoading, selectedIndex, setSelectedIndex, closeMenu } =
        useMentionAutocomplete(value, cursorPosition);

    // Compute dropdown position using a hidden mirror div
    // that replicates textarea styling up to the cursor point
    const updatePosition = useCallback((textarea) => {
        if (!textarea) return;

        // Simple approach: use getBoundingClientRect of the textarea
        // and estimate line position. For single-line mentions this is
        // accurate enough; for multi-line we accept approximate positioning.
        const rect = textarea.getBoundingClientRect();
        setDropdownPosition({
            top: rect.bottom + window.scrollY + 4,
            left: rect.left + window.scrollX,
        });
    }, []);

    const handleChange = useCallback((e) => {
        setValue(e.target.value);
        setCursorPosition(e.target.selectionStart);
        updatePosition(e.target);
    }, [setValue, updatePosition]);

    const handleKeyUp = useCallback((e) => {
        // Update cursor position on arrow keys/home/end etc.
        setCursorPosition(e.target.selectionStart);
    }, []);

    const handleSelect = useCallback((user) => {
        if (!textareaRef?.current) return;

        const textarea = textareaRef.current;
        const textUpToCursor = value.substring(0, cursorPosition);
        const match = textUpToCursor.match(MENTION_TRIGGER_REGEX);
        if (!match) {
            closeMenu();
            return;
        }

        const mentionStart = match.index;
        const insertText = `@${user.username || user.name} `;
        const newValue =
            value.substring(0, mentionStart) +
            insertText +
            value.substring(cursorPosition);

        setValue(newValue);
        closeMenu();

        // Restore focus and cursor
        const newCursor = mentionStart + insertText.length;
        requestAnimationFrame(() => {
            textarea.focus();
            textarea.setSelectionRange(newCursor, newCursor);
        });
    }, [value, cursorPosition, setValue, closeMenu, textareaRef]);

    // Keyboard navigation
    const handleKeyDown = useCallback((e) => {
        if (!isOpen) return;

        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setSelectedIndex((prev) => (prev + 1) % Math.max(results.length, 1));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setSelectedIndex((prev) => (prev - 1 + results.length) % Math.max(results.length, 1));
        } else if ((e.key === 'Enter' || e.key === 'Tab') && results.length > 0) {
            e.preventDefault();
            handleSelect(results[selectedIndex]);
        } else if (e.key === 'Escape') {
            closeMenu();
        }
    }, [isOpen, results, selectedIndex, setSelectedIndex, handleSelect, closeMenu]);

    // Close on outside click
    useEffect(() => {
        if (!isOpen) return;
        const handler = (e) => {
            if (textareaRef?.current && !textareaRef.current.contains(e.target)) {
                closeMenu();
            }
        };
        document.addEventListener('mousedown', handler);
        return () => document.removeEventListener('mousedown', handler);
    }, [isOpen, closeMenu, textareaRef]);

    return {
        textareaProps: {
            onChange: handleChange,
            onKeyDown: handleKeyDown,
            onKeyUp: handleKeyUp,
        },
        dropdownProps: {
            isOpen,
            results,
            isLoading,
            selectedIndex,
            onSelect: handleSelect,
            onHover: setSelectedIndex,
            position: dropdownPosition,
        },
    };
}
```

